var val = Services.getValue(OutstandingAmount.dataBinding);
var err = validateCurrencyValue(val, 999999999.99);
if( null == err )
{	Services.setValue(OutstandingAmount.dataBinding, WPU.formatToTwoDP(val));
}
return err;

